function rootDomain(domain: string | null | undefined): string | null {
  if (!domain) return null
  const d = domain
    .trim()
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split(/[/?#]/)[0]
  return d.includes('.') ? d : null
}

export function CustomerLogo({
  name,
  domain,
  logoUrl,
  size = 24,
  variant = 'token',
  width = 92,
  height = 24,
  className,
}: {
  name: string | null | undefined
  domain: string | null | undefined
  logoUrl?: string | null | undefined
  size?: number
  variant?: 'token' | 'full'
  width?: number
  height?: number
  className?: string
}) {
  const [failed, setFailed] = useState(false)
  const host = rootDomain(domain)
  const storedLogo = logoUrl?.trim()

  if (variant === 'full') {
    if (!storedLogo || failed) {
      return <NameAvatar name={name} size={Math.min(height, size)} className={className} />
    }

    return (
      <img
        src={storedLogo}
        alt=""
        aria-hidden
        width={width}
        height={height}
        onError={() => setFailed(true)}
        className={className}
        style={{
          width,
          height,
          maxWidth: '100%',
          objectFit: 'contain',
          objectPosition: 'left center',
          flexShrink: 0,
        }}
      />
    )
  }

  if (!LOGODEV_TOKEN || !host || failed) {
    return <NameAvatar name={name} size={size} className={className} />
  }

  const src = `https://img.logo.dev/${host}?token=[REDACTED]

  return (
