+                                </div>
+                                <div className="flex h-12 w-36 items-center justify-center rounded-[8px] border bg-background px-2">
+                                  <img src={candidate.url} alt="" aria-hidden className="max-h-9 max-w-full object-contain" />
+                                </div>
+                              </div>
