+                                {candidate.domain ? (
+                                  <Button type="button" size="sm" variant="outline" onClick={() => void saveTokenDomain(candidate.domain!)} disabled={logoBusy}>
+                                    <Search className="size-4" />
+                                    Use as token
+                                  </Button>
+                                ) : null}
+                              </div>
+                            </div>
+                          ))}
+                        </div>
+                      )}
