+                  <div className="mt-4 rounded-[8px] border bg-muted/20 p-4 text-[12.5px] text-muted-foreground">
+                    Click a row to edit uploaded full logos, full logo URLs, and logo.dev token domains.
+                  </div>
+                )}
+              </section>
+            </div>
